#include <bits/stdc++.h>using namespace std; int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);     int t;    cin >> t;    while (t--) {        int n, k;        cin >> n >> k;         if (k < n || k > 2 * n - 1) {            cout << "NO\n";            continue;        }         cout << "YES\n";        vector<int> ans;         int r = k - n + 1;  // block size         if (r == 1) {            ans.push_back(1);            ans.push_back(1);        } else {            ans.push_back(1);            ans.push_back(2);            for (int x = 3; x <= r; x++) {                ans.push_back(x);                ans.push_back(x - 2);            }            ans.push_back(r - 1);            ans.push_back(r);        }         for (int x = r + 1; x <= n; x++) {            ans.push_back(x);            ans.push_back(x);        }         for (int i = 0; i < (int)ans.size(); i++) {            if (i) cout << ' ';            cout << ans[i];        }        cout << '\n';    }     return 0;}